patch:
--- a/adder.v
+++ b/adder.v
@@ -1,12 +1,12 @@
 module adder_4bit(
-  input wire [3:0] a_in,
-  input wire [3:0] b_in,
+  input wire [3:0] operand_a,
+  input wire [3:0] operand_b,
   input wire cin,
   output wire [4:0] sum
 );
   assign sum = a_in + b_in + cin;
 endmodule

 module top;
   wire [3:0] x, y;
   wire c, result;
-  adder_4bit inst (.a_in(x), .b_in(y), .cin(c), .sum(result));
+  adder_4bit inst (.operand_a(x), .operand_b(y), .cin(c), .sum(result));
 endmodule

before_code:
module adder_4bit(
  input wire [3:0] operand_a,
  input wire [3:0] operand_b,
  input wire cin,
  output wire [4:0] sum
);
  assign sum = operand_a + operand_b + cin;
endmodule

module top;
  wire [3:0] x, y;
  wire c, result;
  adder_4bit inst (.a_in(x), .b_in(y), .cin(c), .sum(result));
endmodule

